113→    const mutationReadNotif = useReadNotificationMutation(session);
114→
115→    const handleReadNotif = async(e, notification) => {
116→        e.stopPropagation();
117→        const source = notification?.source || 'journal';
118→        mutationReadNotif.mutate({notifId: notification.id, source})
119→
120→        if(source === 'opinion'){
121→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
122→        } else if(notification?.type === 'follow'){
123→            navigate(`/visitProfile?userId=${notification?.sender_id}`);
124→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
125→            // Navigate to the repost post (quote + embedded original)
126→            const repostId = notification.repost_journal_id;
127→            const encodedId = encodeURIComponent(repostId);
128→            navigate(`/home/post/${encodedId}`);
129→        } else {
130→            handleClickNotif(
131→                e,
132→                null,
133→                '',
